// Script Continued Below

function onSubmit() {
    var formAction = g_form.getActionName();
    if (formAction == 'delete_tasks') {
        confirmDeleteTask();
		// returning true opens UI Page but does not allow user interaction, then auto closes the UI Page
        return false;
    }
}

function confirmDeleteTask() {
    var taskNumberShortDescription = g_form.getValue('taskernumber') + ': ' + g_form.getValue('short_description');
    var messageTitle = getMessage('Delete') + ' ' + taskNumberShortDescription + '?';

    // Use widget for Portal
    if (typeof spModal != 'undefined') {
        spModal.open({
            title: messageTitle,
            backdrop: 'static',
            widget: 'tasker_modal_delete_task_prompt',
            widgetInput: {
                'taskSysId': g_form.getUniqueValue(),
                'taskNumberShortDescription': taskNumberShortDescription
            },
            buttons: [],
			// Hide the <div> with class modal-footer that gets auto inserted from spModal, adds an element style
			footerStyle: { 'display': 'none' }
        }).then(function() {
            //jslog('numberofsubtasks');
        });
        return false;
    } else if (typeof spModal == 'undefined') {
        // For Platform use UI Page named: delete_task_prompt
        var gm = new GlideModal('x_153465_discovert_delete_task_prompt');
        gm.setTitle(messageTitle);
		gm.setPreference('sysparm_taskNumberShortDescription', taskNumberShortDescription);
        gm.setPreference('sysparm_taskSysId', g_form.getUniqueValue());
        gm.setWidth(550);
        gm.render();
    }
}
